package app.org.apache.roller.weblogger.ui.rendering.servlets;

public class MediaResourceServlet extends HttpServlet { private static Log log = LogFactory . getLog ( MediaResourceServlet . class ) ; public void init ( ServletConfig config ) throws ServletException { super . init ( config ) ; log . info ( "Initializing ResourceServlet" ) ; } public void doGet ( HttpServletRequest request , HttpServletResponse response ) throws ServletException , IOException { MediaFileManager mfMgr = WebloggerFactory . getWeblogger ( ) . getMediaFileManager ( ) ; Weblog weblog ; WeblogMediaResourceRequest resourceRequest ; try { resourceRequest = new WeblogMediaResourceRequest ( request ) ; weblog = resourceRequest . getWeblog ( ) ; if ( weblog == null ) { throw new WebloggerException ( "unable to lookup weblog: " + resourceRequest . getWeblogHandle ( ) ) ; } } catch ( Exception e ) { log . debug ( "error creating weblog resource request" , e ) ; response . sendError ( HttpServletResponse . SC_NOT_FOUND ) ; return ; } long resourceLastMod ; InputStream resourceStream = null ; MediaFile mediaFile ; try { mediaFile = mfMgr . getMediaFile ( resourceRequest . getResourceId ( ) , true ) ; resourceLastMod = mediaFile . getLastModified ( ) ; } catch ( Exception ex ) { log . debug ( "Unable to get resource" , ex ) ; response . sendError ( HttpServletResponse . SC_NOT_FOUND ) ; return ; } if ( ModDateHeaderUtil . respondIfNotModified ( request , response , resourceLastMod , resourceRequest . getDeviceType ( ) ) ) { return ; } else { ModDateHeaderUtil . setLastModifiedHeader ( response , resourceLastMod , resourceRequest . getDeviceType ( ) ) ; } if ( resourceRequest . isThumbnail ( ) ) { response . setContentType ( "image/png" ) ; try { resourceStream = mediaFile . getThumbnailInputStream ( ) ; } catch ( Exception e ) { if ( log . isDebugEnabled ( ) ) { log . debug ( "ERROR loading thumbnail for " + mediaFile . getId ( ) , e ) ; } else { log . warn ( "ERROR loading thumbnail for " + mediaFile . getId ( ) ) ; } } } if ( resourceStream == null ) { response . setContentType ( mediaFile . getContentType ( ) ) ; resourceStream = mediaFile . getInputStream ( ) ; } OutputStream out ; try { byte [ ] buf = new byte [ RollerConstants . EIGHT_KB_IN_BYTES ] ; int length ; out = response . getOutputStream ( ) ; while ( ( length = resourceStream . read ( buf ) ) > 0 ) { out . write ( buf , 0 , length ) ; } out . close ( ) ; } catch ( Exception ex ) { log . error ( "ERROR" , ex ) ; if ( ! response . isCommitted ( ) ) { response . reset ( ) ; response . sendError ( HttpServletResponse . SC_INTERNAL_SERVER_ERROR ) ; } } finally { resourceStream . close ( ) ; } } }